import React, { useState, useEffect, useRef } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";

// ==================== مكون قائمة الطلبات ====================
const OrderList = ({ orders, onUpdateOrderStatus }) => {
  const [selectedGroup, setSelectedGroup] = useState(null);
  const containerRef = useRef(null);
  const [showScrollButton, setShowScrollButton] = useState(false);

  // تجميع الطلبات المتطابقة (نفس المنتج)
  const groupOrders = () => {
    const groups = {};
    orders.forEach(order => {
      const key = `${order.name}_${order.price}`;
      if (!groups[key]) {
        groups[key] = {
          id: key,
          name: order.name,
          price: order.price,
          quantity: 0,
          orders: [],
          status: order.status
        };
      }
      groups[key].quantity++;
      groups[key].orders.push(order);
      // إذا كان أي طلب في المجموعة ملغي أو مكتمل، نحدد الحالة العامة
      if (order.status === 'cancelled') groups[key].status = 'cancelled';
      else if (order.status === 'completed') groups[key].status = 'completed';
      else groups[key].status = 'pending';
    });
    return Object.values(groups);
  };

  const orderGroups = groupOrders();

  // التمرير التلقائي للأسفل عند إضافة طلب جديد
  useEffect(() => {
    if (containerRef.current) {
      containerRef.current.scrollTop = containerRef.current.scrollHeight;
    }
  }, [orders]);

  // إظهار زر التمرير عند overflow
  const handleScroll = () => {
    if (containerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = containerRef.current;
      setShowScrollButton(scrollHeight - scrollTop > clientHeight + 50);
    }
  };

  const scrollToTop = () => {
    if (containerRef.current) {
      containerRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // عرض تفاصيل مجموعة طلبات - تبقى مفتوحة حتى يغلقها المستخدم
  const GroupDetailModal = ({ group, onClose }) => {
    const [showIndividualOrders, setShowIndividualOrders] = useState(false);
    
    // دالة لتحديث حالة طلبية فردية - لا تغلق النافذة
    const handleUpdateSingleOrder = (orderId, newStatus) => {
      onUpdateOrderStatus(orderId, newStatus);
      // لا نغلق النافذة - نتركها مفتوحة
    };
    
    // دالة لتحديث جميع طلبات المجموعة - لا تغلق النافذة
    const handleUpdateAllOrders = (newStatus) => {
      group.orders.forEach(order => onUpdateOrderStatus(order.id, newStatus));
      // لا نغلق النافذة - نتركها مفتوحة
    };
    
    return (
      <div className="modal-overlay" onClick={onClose}>
        <div className="modal-content-order" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '500px' }}>
          <button onClick={onClose} className="close-btn">✕</button>
          <div className="text-center">
            <div className="text-5xl mb-3">📦</div>
            <h3 className="text-xl font-bold text-white mb-2">{group.name}</h3>
            <div className="order-detail-info">
              <p><span className="detail-label">💰 السعر للواحدة:</span> {group.price} دج</p>
              <p><span className="detail-label">🔢 العدد الإجمالي:</span> {group.quantity}</p>
              <p><span className="detail-label">💵 السعر الإجمالي:</span> {group.price * group.quantity} دج</p>
              <p><span className="detail-label">📋 الحالة:</span> 
                <span className={`status-badge-detail ${group.status}`}>
                  {group.status === 'pending' ? 'في الانتظار' : group.status === 'completed' ? 'تم التوصيل' : 'ملغي'}
                </span>
              </p>
            </div>
            
            {/* أزرار التحكم للمجموعة كاملة */}
            <div className="order-detail-buttons" style={{ marginBottom: '15px', flexWrap: 'wrap' }}>
              <button onClick={() => handleUpdateAllOrders('completed')} className="btn-livre">
                ✅ Livrée (الكل)
              </button>
              <button onClick={() => handleUpdateAllOrders('cancelled')} className="btn-annule">
                ❌ Annulée (الكل)
              </button>
              <button onClick={() => handleUpdateAllOrders('pending')} className="btn-primary" style={{ background: 'linear-gradient(135deg, #f59e0b, #d97706)' }}>
                🔄 Remettre (الكل)
              </button>
            </div>
            
            {/* زر عرض تفاصيل كل طلبية على حدة */}
            <button 
              onClick={() => setShowIndividualOrders(!showIndividualOrders)}
              className="btn-primary w-full mb-3"
              style={{ background: 'linear-gradient(135deg, #3b82f6, #1d4ed8)' }}
            >
              {showIndividualOrders ? '📋 إخفاء التفاصيل' : '🔍 عرض تفاصيل كل طلبية'}
            </button>
            
            {/* عرض قائمة الطلبات الفردية داخل المجموعة */}
            {showIndividualOrders && (
              <div className="individual-orders-list" style={{ 
                maxHeight: '300px', 
                overflowY: 'auto', 
                marginTop: '10px',
                borderTop: '1px solid rgba(255,255,255,0.1)',
                paddingTop: '15px'
              }}>
                <h4 className="text-white font-bold mb-3 text-center">📋 الطلبات الفردية:</h4>
                {group.orders.map((order, idx) => (
                  <div 
                    key={order.id} 
                    className="individual-order-item"
                    style={{
                      background: 'rgba(255,255,255,0.05)',
                      borderRadius: '10px',
                      padding: '10px',
                      marginBottom: '10px',
                      display: 'flex',
                      justifyContent: 'space-between',
                      alignItems: 'center',
                      borderLeft: `3px solid ${order.status === 'cancelled' ? '#ef4444' : order.status === 'completed' ? '#3b82f6' : '#22c55e'}`
                    }}
                  >
                    <div style={{ textAlign: 'left', flex: 1 }}>
                      <div className="text-white text-sm">
                        🆔 طلب #{order.id}
                      </div>
                      <div className="text-gray-400 text-xs">
                        🕐 {order.time || 'الآن'}
                      </div>
                      {order.notes && (
                        <div className="text-yellow-400 text-xs">
                          📝 {order.notes}
                        </div>
                      )}
                      <div className="text-xs mt-1">
                        <span className={`status-badge-detail ${order.status}`} style={{ fontSize: '10px', padding: '2px 6px' }}>
                          {order.status === 'pending' ? '⏳ قيد الانتظار' : order.status === 'completed' ? '✅ مكتمل' : '❌ ملغي'}
                        </span>
                      </div>
                    </div>
                    <div className="individual-order-actions" style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleUpdateSingleOrder(order.id, 'completed');
                        }}
                        className="btn-livre"
                        style={{ padding: '5px 12px', fontSize: '12px' }}
                      >
                        ✅ Livrée
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleUpdateSingleOrder(order.id, 'cancelled');
                        }}
                        className="btn-annule"
                        style={{ padding: '5px 12px', fontSize: '12px' }}
                      >
                        ❌ Annulée
                      </button>
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          handleUpdateSingleOrder(order.id, 'pending');
                        }}
                        className="btn-primary"
                        style={{ padding: '5px 12px', fontSize: '12px', background: 'linear-gradient(135deg, #f59e0b, #d97706)' }}
                      >
                        🔄 Remettre
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
            
            <div className="mt-3 text-sm text-gray-400">
              <p>📌 {group.orders.filter(o => o.status === 'pending').length} / {group.quantity} طلبية قيد الانتظار</p>
              <p className="text-xs mt-1">💡 يمكن تغيير حالة أي طلبية في أي وقت - النافذة تبقى مفتوحة</p>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="order-list-container" style={{ width: '95%', maxWidth: '800px', margin: '20px auto' }}>
      <div className="order-list-header">
        <h3 className="order-list-title">
          📋 قائمة الطلبات
          <span className="order-count-badge">{orders.length}</span>
        </h3>
        <div className="header-actions">
          <button className="refresh-btn" onClick={() => window.location.reload()}>
            🔄
          </button>
        </div>
      </div>
      
      <div 
        ref={containerRef}
        className="order-list-scroll"
        onScroll={handleScroll}
        style={{ 
          maxHeight: '500px',
          overflowY: 'auto',
          transition: 'max-height 0.3s ease'
        }}
      >
        {orderGroups.length === 0 ? (
          <div className="empty-orders">
            <div className="empty-icon">🍽️</div>
            <p>لا توجد طلبات حالياً</p>
            <p className="empty-sub">ستظهر الطلبات هنا تلقائياً</p>
          </div>
        ) : (
          orderGroups.map((group, idx) => (
            <div 
              key={group.id}
              className={`order-item ${group.status} animate-slide-up`}
              style={{ animationDelay: `${idx * 0.05}s` }}
            >
              <div className="order-item-content">
                <div 
                  className="order-info"
                  onClick={() => setSelectedGroup(group)}
                  style={{ cursor: 'pointer', flex: 1 }}
                >
                  <span className="order-icon">
                    {group.name.includes('قهوة') ? '☕' : 
                     group.name.includes('شاي') ? '🍵' :
                     group.name.includes('بيتزا') ? '🍕' :
                     group.name.includes('برغر') ? '🍔' : '🍽️'}
                  </span>
                  <div className="order-details">
                    <div className="order-name">{group.name}</div>
                    <div className="order-meta">
                      <span className="order-price">{group.price} دج</span>
                      {group.quantity > 1 && (
                        <span className="order-quantity-badge">×{group.quantity}</span>
                      )}
                    </div>
                  </div>
                </div>
                <div className="order-actions">
                  {group.quantity > 1 && (
                    <span className="group-badge">
                      {group.quantity} عناصر
                    </span>
                  )}
                  {/* أزرار التحكم المباشرة */}
                  <div className="action-buttons-group" style={{ display: 'flex', gap: '8px' }}>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        group.orders.forEach(order => onUpdateOrderStatus(order.id, 'completed'));
                      }}
                      className="btn-livre-small"
                      style={{
                        background: 'linear-gradient(135deg, #22c55e, #15803d)',
                        border: 'none',
                        padding: '5px 12px',
                        borderRadius: '15px',
                        color: 'white',
                        fontSize: '11px',
                        fontWeight: 'bold',
                        cursor: 'pointer',
                        transition: 'all 0.2s'
                      }}
                    >
                      ✅ Livrée
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        group.orders.forEach(order => onUpdateOrderStatus(order.id, 'cancelled'));
                      }}
                      className="btn-annule-small"
                      style={{
                        background: 'linear-gradient(135deg, #ef4444, #b91c1c)',
                        border: 'none',
                        padding: '5px 12px',
                        borderRadius: '15px',
                        color: 'white',
                        fontSize: '11px',
                        fontWeight: 'bold',
                        cursor: 'pointer',
                        transition: 'all 0.2s'
                      }}
                    >
                      ❌ Annulée
                    </button>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        group.orders.forEach(order => onUpdateOrderStatus(order.id, 'pending'));
                      }}
                      className="btn-pending-small"
                      style={{
                        background: 'linear-gradient(135deg, #f59e0b, #d97706)',
                        border: 'none',
                        padding: '5px 12px',
                        borderRadius: '15px',
                        color: 'white',
                        fontSize: '11px',
                        fontWeight: 'bold',
                        cursor: 'pointer',
                        transition: 'all 0.2s'
                      }}
                    >
                      🔄 Remettre
                    </button>
                  </div>
                  <div className={`order-status ${group.status}`}>
                    {group.status === 'pending' ? '⏳' : group.status === 'completed' ? '✅' : '❌'}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
      
      {showScrollButton && (
        <button className="scroll-to-top" onClick={scrollToTop}>
          ↑
        </button>
      )}
      
      {/* مودال التفاصيل - يفتح فقط عند الضغط على اسم الطلبية ويبقى مفتوحاً حتى يغلقه المستخدم */}
      {selectedGroup && (
        <GroupDetailModal 
          group={selectedGroup} 
          onClose={() => setSelectedGroup(null)} 
        />
      )}
    </div>
  );
};

// ==================== مكون تعديل CV ====================
const EditCVModal = ({ workerInfo, onSave, onClose }) => {
  const [editedInfo, setEditedInfo] = useState({ ...workerInfo });
  const [newSkill, setNewSkill] = useState("");

  const addSkill = () => {
    if (newSkill.trim() && !editedInfo.skills.includes(newSkill.trim())) {
      setEditedInfo({
        ...editedInfo,
        skills: [...editedInfo.skills, newSkill.trim()]
      });
      setNewSkill("");
    }
  };

  const removeSkill = (skillToRemove) => {
    setEditedInfo({
      ...editedInfo,
      skills: editedInfo.skills.filter(skill => skill !== skillToRemove)
    });
  };

  const handleSave = () => {
    onSave(editedInfo);
    onClose();
  };

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '600px' }}>
        <button onClick={onClose} className="close-btn">✕</button>
        <div className="text-center">
          <div className="text-5xl mb-4">✏️</div>
          <h2 className="text-2xl font-bold text-white mb-4">تعديل السيرة الذاتية</h2>
        </div>
        
        <div className="edit-cv-form">
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">👤 الاسم الكامل</label>
            <input 
              type="text" 
              className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
              value={editedInfo.name}
              onChange={(e) => setEditedInfo({...editedInfo, name: e.target.value})}
            />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">💼 المسمى الوظيفي</label>
            <input 
              type="text" 
              className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
              value={editedInfo.role}
              onChange={(e) => setEditedInfo({...editedInfo, role: e.target.value})}
            />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📧 البريد الإلكتروني</label>
            <input 
              type="email" 
              className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
              value={editedInfo.email}
              onChange={(e) => setEditedInfo({...editedInfo, email: e.target.value})}
            />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📱 رقم الهاتف</label>
            <input 
              type="tel" 
              className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
              value={editedInfo.phone}
              onChange={(e) => setEditedInfo({...editedInfo, phone: e.target.value})}
            />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📍 الموقع</label>
            <input 
              type="text" 
              className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
              value={editedInfo.location}
              onChange={(e) => setEditedInfo({...editedInfo, location: e.target.value})}
            />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">📝 السيرة الذاتية (Bio)</label>
            <textarea 
              className="w-full p-3 rounded-xl bg-white/10 text-white border border-green-500/30"
              rows="3"
              value={editedInfo.bio}
              onChange={(e) => setEditedInfo({...editedInfo, bio: e.target.value})}
            />
          </div>
          
          <div className="mb-4">
            <label className="text-white text-sm block mb-2">💪 المهارات</label>
            <div className="flex flex-wrap gap-2 mb-2">
              {editedInfo.skills.map((skill, i) => (
                <span key={i} className="skill-tag" style={{ display: 'inline-flex', alignItems: 'center', gap: '5px' }}>
                  {skill}
                  <button onClick={() => removeSkill(skill)} style={{ background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '14px' }}>✕</button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input 
                type="text" 
                className="flex-1 p-2 rounded-xl bg-white/10 text-white border border-green-500/30"
                placeholder="أضف مهارة جديدة"
                value={newSkill}
                onChange={(e) => setNewSkill(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && addSkill()}
              />
              <button onClick={addSkill} className="btn-primary">+ إضافة</button>
            </div>
          </div>
          
          <button onClick={handleSave} className="btn-primary w-full mt-4">
            💾 حفظ التغييرات
          </button>
        </div>
      </div>
    </div>
  );
};

// ==================== المكون الرئيسي ====================
export default function Profileemploye() {
  const [showWorkerCV, setShowWorkerCV] = useState(false);
  const [showManagerCV, setShowManagerCV] = useState(false);
  const [showAddComment, setShowAddComment] = useState(false);
  const [showCommentsList, setShowCommentsList] = useState(false);
  const [showEditCV, setShowEditCV] = useState(false);
  const [workerStatus, setWorkerStatus] = useState("working");
  const [currentWorkPlace, setCurrentWorkPlace] = useState("Le Café Paris");
  
  // ========== حالة الطلبات (تأتي من الـ Backend) ==========
  const [orders, setOrders] = useState([
    { id: 1, name: "قهوة عربية", price: 150, status: "pending", time: "14:30", notes: "سكر أقل" },
    { id: 2, name: "شاي بالنعناع", price: 120, status: "pending", time: "14:32", notes: "" },
    { id: 3, name: "قهوة عربية", price: 150, status: "pending", time: "14:35", notes: "بدون سكر" },
    { id: 4, name: "كابتشينو", price: 250, status: "pending", time: "14:38", notes: "حليب ساخن" },
    { id: 5, name: "قهوة عربية", price: 150, status: "pending", time: "14:40", notes: "" },
    { id: 6, name: "شاي بالنعناع", price: 120, status: "pending", time: "14:42", notes: "نعناع طازج" },
  ]);
  
  const [comments, setComments] = useState([
